const raw = $input.item.json.text || $input.item.json.output || $input.item.json.response;

// Clean up in case the model wrapped it in markdown code blocks
const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();

const posts = JSON.parse(cleaned);

return {
  json: {
    title: $('RSS Feed Trigger').item.json.title,
    link: $('RSS Feed Trigger').item.json.link,
    linkedin: posts.linkedin,
    twitter: posts.twitter,
    instagram: posts.instagram
  }
};

